codeExercises.solution:
import React, { useState } from 'react';

const ColumnList = () => {
  const [columns, setColumns] = useState([{ _id: '1', title: 'Cột 1' }]);

  const handleAddNewColumn = (newColumn) => {
    setColumns([...columns, newColumn]);
  };

  return (
    <div>
      <button onClick={() => handleAddNewColumn({ _id: '2', title: 'Cột 2' })}>
        Thêm Cột Mới (Giả lập)
      </button>
      <ul>
        {columns.map(c => <li key={c._id}>{c.title}</li>)}
      </ul>
    </div>
  );
};

export default ColumnList;

